SELECT *
FROM main_policy_master
WHERE policy_no = #{policyNo}
  AND policy_seq = #{policySeq}

SELECT *
FROM main_policy_address
WHERE policy_no = #{policyNo}
  AND policy_seq = #{policySeq}
  AND address_type = #{addressType}

SELECT *
FROM main_policy_address
WHERE policy_no = #{policyNo}
  AND policy_seq = #{policySeq}
ORDER BY address_type

SELECT *
FROM main_policy_ride
WHERE policy_no = #{policyNo}
  AND policy_seq = #{policySeq}
ORDER BY ride_order

SELECT code_group,
       code_field,
       code_before,
       code_after,
       code_description
FROM code_description
WHERE code_group = #{codeGroup}
  AND code_field = #{codeField}
  AND code_before = #{codeBefore}

SELECT COUNT(*)
FROM policy_change_acceptance
WHERE change_case_no = #{changeCaseNo}

SELECT change_item
FROM policy_change_item
WHERE policy_no = #{policyNo}
  AND policy_seq = #{policySeq}
  AND change_case_no = #{changeCaseNo}
ORDER BY change_item

SELECT COUNT(*)
FROM policy_change_item
WHERE policy_no = #{policyNo}
  AND policy_seq = #{policySeq}
  AND change_case_no = #{changeCaseNo}
  AND change_item = #{changeItem}

mapper.update:
UPDATE policy_change_acceptance
SET acceptance_status = #{acceptanceStatus}
WHERE policy_no = #{policyNo}
  AND policy_seq = #{policySeq}
  AND change_case_no = #{changeCaseNo}

UPDATE main_policy_address
SET zip_code3 = #{zipCode3},
    zip_code2 = #{zipCode2},
    full_width_address = #{fullWidthAddress},
    half_width_address = #{halfWidthAddress}
WHERE policy_no = #{policyNo}
  AND policy_seq = #{policySeq}
  AND address_type = #{addressType}

UPDATE main_policy_master
main_product_code = #{contentAfter}, main_policy_years = CAST(#{contentAfter} AS SIGNED), insured_amount = CAST(#{contentAfter} AS DECIMAL(10, 2)), premium = CAST(#{contentAfter} AS DECIMAL(17, 4)),
WHERE policy_no = #{policyNo} AND policy_seq = #{policySeq}

UPDATE main_policy_ride
SET insured_amount = CAST(#{insuredAmount} AS DECIMAL(10, 2))
WHERE policy_no = #{policyNo}
  AND policy_seq = #{policySeq}
  AND ride_order = #{rideOrder}

UPDATE main_policy_ride
SET premium = CAST(#{premium} AS DECIMAL(17, 4))
WHERE policy_no = #{policyNo}
  AND policy_seq = #{policySeq}
  AND ride_order = #{rideOrder}

UPDATE main_policy_master
SET premium = (
    SELECT COALESCE(SUM(ride.premium), 0)
    FROM main_policy_ride ride
    WHERE ride.policy_no = #{policyNo}
      AND ride.policy_seq = #{policySeq}
)
WHERE policy_no = #{policyNo}
  AND policy_seq = #{policySeq}
